def separate_paren_groups(paren_string: str) -> List[str]:
    """ Input to this function is a string containing multiple groups of nested parentheses. Your goal is to
    separate those group into separate strings and return the list of those.
    Separate groups are balanced (each open brace is properly closed) and not nested within each other
    Ignore any spaces in the input string.
    >>> separate_paren_groups('( ) (( )) (( )( ))')
    ['()', '(())', '(()())']
    """
    result = []
    current_group = []
    left_brace_depth = 0
    right_brace_depth = 0
    in_stack = False

    for char in paren_string:
        if char == '{':
            if in_stack:
                left_brace_depth += 1
            else:
                in_stack = True
        elif char == '}':
            if in_stack:
                right_brace_depth += 1
            else:
                in_stack = False
                if right_brace_depth != left_brace_depth:
                    result.append(''.join(current_group))
                    current_group = []
                else:
                    # Found an unbalanced closing brace; close remaining open ones in the current group
                    for _ in range(left_brace_depth - right_brace_depth):
                        current_group.pop()
                    current_group = []
                    result.append(''.join(current_group))
                    current_group = []
                    in_stack = False
        else:
            # Non-brace character: ignore
            pass

    # If the string ends with an unbalanced open brace, add the current group
    if in_stack:
        result.append(''.join(current_group))

    return result

