    """
    Input to this function is a string represented multiple groups for nested parentheses separated by spaces.
    For each of the group, output the deepest level of nesting of parentheses.
    E.g. (()()) has maximum two levels of nesting while ((())) has three.

    >>> parse_nested_parens('(()()) ((())) () ((())()())')
    [2, 3, 1, 3]
    """
    if not paren_string:
        return []

    stack = []
    results = []
    n = len(paren_string)

    for i in range(n):
        c = paren_string[i]
        if c == ')':
            if not stack:
                results.append(0)
                break
            top = stack.pop()
            if c == '(':
                stack.append(top + 1)
            else:
                top = stack.pop()
                if top < 0:
                    results.append(0)
                elif top == 0:
                    results.append(1)
                    stack.pop()
                else:
                    results.append(2)
        elif c == ' ':
            results.append(1)

    return results

