    def xor_digits(s1: str, s2: str) -> str:
        """ XOR two decimal strings representing integers """
        xor_str = []
        for ch in s1 + s2:
            xor_str.append("0" if ch else "1")
        return "".join(ch for ch in xor_str if ch)

    def xor_str_digits(s1: str, s2: str) -> str:
        """ XOR two binary strings representing integers """
        xor_str = []
        for i in range(len(s1) + len(s2)):
            if i < len(s1):
                xor_str.append(s1[i])
            if i < len(s2):
                xor_str.append(s2[i])
        return "".join(xor_str)

    return xor_str_digits(a, b)


