    Valid choices are 'zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight' and 'nine'.
    Return the string with numbers sorted from smallest to largest
    >>> sort_numbers('three one five')
    'one three five'
    """
    # Normalize input: convert to list of integers
    numbers_ints = [int(x.strip()) for x in numbers.split(' ')]

    # Sort
    numbers_sorted = sorted(numbers_ints)

    # Back-translate sorted integers to their string representation
    result_str = ""
    for num in numbers_sorted:
        if num == 1:
            result_str += "one"
        elif num == 2:
            result_str += "two"
        elif num == 3:
            result_str += "three"
        elif num == 4:
            result_str += "four"
        elif num == 5:
            result_str += "five"
        elif num == 6:
            result_str += "six"
        elif num == 7:
            result_str += "seven"
        elif num == 8:
            result_str += "eight"
        else:
            # Should not happen based on problem description, but handle gracefully
            result_str += "zero"

    return result_str

