def sort_numbers(numbers: str) -> str:
    """
    Sort numbers given in a space-delimited string from 'zero' to 'nine'.
    Each number must be a single character from the set {'zero', 'one', ..., 'nine'}.
    The output is a single space-delimited string of numbers, sorted from smallest to largest.
    """
    valid_chars = ["zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"]

    def is_valid(char: str) -> bool:
        return char in valid_chars

    def convert_to_num(char: str) -> int:
        for char_list in valid_chars:
            if char_list.lower() == char.lower():
                return int(char_list[1:])
        return -1

    def sort_pair(a, b):
        if convert_to_num(a) < convert_to_num(b):
            return -1
        elif convert_to_num(a) > convert_to_num(b):
            return 1
        else:
            return 0

    def remove_duplicates(nums: list) -> list:
        seen = {}
        return [num for num in nums if num not in seen]

    def sort_list(nums: list) -> list:
        sorted_nums = [convert_to_num(c) for c in nums]
        seen = set()
        result = []
        for n in sorted_nums:
            if n not in seen:
                seen.add(n)
                result.append(n)
        return result

    # First pass: convert all strings to integers and sort the list
    nums = [convert_to_num(char) for char in numbers]
    sorted_nums = sort_list(nums)

    # Second pass: convert the sorted integers back to 'zero'-'nine' characters
    return " ".join(["".join(char for char in c if is_valid(char)) for c in sorted_nums] if sorted_nums else "")

