            n //= 7

        while n > 1:
            if n % 11 == 0:
                result.append(11)
                count += 1
            else:
                break
            n //= 11

        while n > 1:
            if n % 13 == 0:
                result.append(13)
                count += 1
            else:
                break
            n //= 13

        while n > 1:
            if n % 17 == 0:
                result.append(17)
