            n //= 19
            break

        while n > 1:
            if n % 23 == 0:
                result.append(23)
                count += 1
            else:
                break
            n //= 23
            break
        if count == 0:
            break

        while n > 1:
            if n % 29 == 0:
                result.append(29)
                count += 1
            else:
                break
            n //= 29
            break

        while n > 1:
            if n % 31 == 0:
                result.append(31)
