    >>> is_palindrome('aba')
    True
    >>> is_palindrome('aaaaa')
    True
    >>> is_palindrome('zbcd')
    False
    """
    def is_palindrome_recursive(s: str, left: int = 0, right: int = len(s) - 1) -> bool:
        if left >= right:
            return True
        if s[left] != s[right]:
            return False
        return is_palindrome_recursive(s, left + 1, right - 1)

    return is_palindrome_recursive(text)

