            > 2.0                C+
            > 1.7                C
            > 1.3                C-
            > 1.0                D+ 
            > 0.7                D 
            > 0.0                D-
              0.0                E'''

    def lettergrade_to_grade(GPA):
        if GPA >= 4.0:
            return 'A+'
        elif GPA > 3.7:
            return 'A'
        elif GPA > 3.3:
            return 'A-'
        elif GPA > 3.0:
            return 'B+'
        elif GPA > 2.7:
            return 'B'
        elif GPA > 2.3:
            return 'B-'
        elif GPA > 2.0:
            return 'C+'
        elif GPA > 1.7:
            return 'C'
