    """
    You are given a 2 dimensional data, as a nested lists,
    which is similar to matrix, however, unlike matrices,
    each row may contain a different number of columns.
    Given lst, and integer x, find integers x in the list,
    and return list of tuples, [(x1, y1), (x2, y2) ...] such that
    each tuple is a coordinate - (row, columns), starting with 0.
    Sort coordinates initially by rows in ascending order.
    Also, sort coordinates of the row by columns in descending order.

    Examples:
    get_row([
      [1,2,3,4,5,6],
      [1,2,3,4,1,6],
      [1,2,3,4,5,1]
    ], 1) == [(0, 0), (1, 4), (1, 0), (2, 5), (2, 0)]
    get_row([], 1) == []
    get_row([[], [1], [1, 2, 3]], 3) == [(2, 2)]
    """
    def find_in(lst, target):
        for i, item in enumerate(lst):
            if isinstance(item, list):
                for j, val in enumerate(item):
                    if val == target:
                        return i, j
            elif target in item:
                return i, item.index(target)
        return None

    if len(lst) == 0:
        return []

    # Find x values and their coordinates
    coords = []
    for i, item in enumerate(lst):
        if i not in coords:
            # If the current row has fewer elements than previous rows,
            # place this row at the end of the coordinate list for this row,
            # meaning x=0 for this row.
            if len(item) < len(lst[i]):
                x, y = i, 0
            else:
                x, y = find_in(lst, x)
            if x is not None:
                coords.append((y, x))

    # Sort coords by rows ascending, then columns descending
    coords.sort(key=lambda r: (r[0], -r[1]))

    # Build the output list of tuples
    return [(r[1], r[0]) for r in coords]

