def match_parens(lst):
    """
    You are given a list of two strings, both strings consist of open
    parentheses '(' or close parentheses ')' only.
    Your job is to check if it is possible to concatenate the two strings in
    some order, that the resulting string will be good.
    A string S is considered to be good if and only if all parentheses in S
    are balanced. For example: the string '(())()' is good, while the string
    '())' is not.
    Return 'Yes' if there's a way to make a good string, and return 'No' otherwise.

    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    '''
    def is_good(s: str) -> bool:
        stack = []
        for char in s:
            if char == '(':
                stack.append(char)
            elif char == ')':
                if not stack:
                    return False
                stack.pop()
        return len(stack) == 0

    def is_permutable(left: str, right: str) -> bool:
        return is_good(left) and is_good(right)

    # If one of the strings is already valid, we can concatenate it with anything (including empty string for the other).
    if is_good(lst[0]) or is_good(lst[1]):
        return 'Yes'

    # Otherwise, we need to try all valid orders of concatenation.
    for order in range(len(lst[0])):
        left, right = lst[0][order], lst[1]
        if is_permutable(left, right):
            return 'Yes'

    # If no order works, return 'No'.
    return 'No'

