    check_if_last_char_is_a_letter("") ➞ False 
    """
    if not isinstance(txt, str):
        return False

    if txt.strip():
        if txt[-1].isalpha():
            if txt[-1].isalnum():
                return False
        elif not txt[-1].isalpha():
            return False
    else:
        return False

