def simplify(x, n):
    """Your task is to implement a function that will simplify the expression
    x * n. The function returns True if x * n evaluates to a whole number and False
    otherwise. Both x and n, are string representation of a fraction, and have the following format,
    <numerator>/<denominator> where both numerator and denominator are positive whole numbers.

    You can assume that x, and n are valid fractions, and do not have zero as denominator.
    """
    def remove_zero_denom(s):
        parts = s.split('/')
        num_str = parts[0].replace(',', '')
        den_str = parts[1].replace(',', '')
        num = int(num_str)
        den = int(den_str)
        return num, den

    def simplify_fraction(x_str, n_str):
        x, n = remove_zero_denom(x_str), remove_zero_denom(n_str)
        x_numerator, x_denominator = int(x[0]), int(x[1])
        n_numerator, n_denominator = int(n[0]), int(n[1])

        # Handle cases where one of the fractions is 1:5 (numerator=0)
        if x_numerator == 0 and n_denominator != 0:
            return True
        if n_numerator == 0 and x_denominator != 0:
            return False

        if x_denominator == 0 or n_denominator == 0:
            return False

        # Ensure denominators are positive
        if x_denominator < 0 or n_denominator < 0:
            return False

        # Simplify the fraction using GCD
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a

        x_gcd, n_gcd = gcd(x_denominator, n_denominator)
        if x_denominator == 0 or n_denominator == 0:
            return True  # If the denominator becomes zero after simplifying, it means it's an integer (positive or negative)

        # Check if numerator is divisible by the GCD
        if x_numerator % x_gcd != 0:
            return False
        if n_numerator % n_gcd != 0:
            return False

        # Both conditions are met, return True
        return True

    # Apply the function to the input strings
    return simplify_fraction(x, n)

def order_by_points(nums):
    """
    Write a function which sorts the given list of integers
    in ascending order according to the sum of their digits.
    Note: if there are several items with similar sum of their digits,
    order them based on their index in original list.

    For example:
    >>> order_by_points([1, 11, -1, -11, -12]) == [-1, -11, 1, -12, 11]
    >>> order_by_points([]) == []
    """
    def get_digit_sum(n):
        if n == 0:
            return 0
        return sum(int(d) for d in str(abs(n)))

    def sort_key(item):
        digit_sum = get_digit_sum(item)
        # For same digit_sum, keep original index
        return (digit_sum, item)

    return sorted(nums, key=sort_key)

