    order them based on their index in original list.

    For example:
    >>> order_by_points([1, 11, -1, -11, -12]) == [-1, -11, 1, -12, 11]
    >>> order_by_points([]) == []
    """
    def compute_digits(x):
        digits = [int(d) for d in str(abs(x))]
        digits.sort(reverse=True)
        return sum(digits)

    def sort_key(x):
        return (compute_digits(x), x, x)

    def primary_key(val1, val2):
        if val1 < val2:
            return -1
        elif val1 > val2:
            return 1
        return 0

    def secondary_key(val1, val2):
        return val2[0] - val1[0]

    nums.sort(key=lambda x: (sort_key(x), secondary_key(x, x)))
    return nums

def order_by_points(nums):
