    For example:
    >>> order_by_points([1, 11, -1, -11, -12]) == [-1, -11, 1, -12, 11]
    >>> order_by_points([]) == []
    """
    def sum_digits(n):
        if n < 0:
            n = -n
        return sum(int(d) for d in str(n))

    # Group numbers by sum of their digits
    groups = {}
    for n in nums:
        groups[sum_digits(n)] = groups.get(sum_digits(n), []) + [n]

    # Sort groups by sum of digits, then by index
    result = []
    for n in groups.values():
        result.append(n)

    return result

