        num = -num
        odd_count = 0
    else:
        odd_count = 0

    # Count odd and even digits of absolute value
    while num > 0:
        digit = num % 10
        if digit % 2 != 0:
            odd_count += 1
        else:
            even_count += 1
        num //= 10

    return tuple(sorted([even_count, odd_count]))

